UPDATE quiz_submissions SET percentage = ROUND((score::numeric / NULLIF(max_score, 0)) * 100) WHERE id = 'a52d4d8e-0a3d-4bce-b770-ec8d519e4037' AND percentage IS NULL; UPDATE group_student_progress SET status = 'graded', exam_submitted_at = NOW(), graded_at = NOW(), status_changed_at = NOW(), updated_at = NOW() WHERE id = '3a479f81-0a1c-4b66-a9b8-021ec5a130f9' AND student_id = 'cfd79ba3-fb3c-4613-a6cc-84a08d56ccda'; UPDATE exam_live_progress SET status = 'submitted' WHERE student_id = 'cfd79ba3-fb3c-4613-a6cc-84a08d56ccda' AND status != 'submitted';